import { useState, useEffect, useCallback } from 'react';
import { supabase } from '../../supabaseClient';

export interface RawFile {
    id: string;
    file_name: string;
    file_url: string;
    file_type: 'pdf' | 'audio' | 'image';
    file_size: number;
    mime_type?: string;
    storage_path: string;
    bucket_name: string;
    metadata: Record<string, any>;
    duration_seconds?: number;
    page_count?: number;
    imported_by?: string;
    imported_at: string;
    is_deleted: boolean;
    deleted_at?: string;
    deleted_by?: string;
    created_at: string;
    updated_at: string;
}

export interface UseRawFilesReturn {
    rawFiles: RawFile[];
    loading: boolean;
    error: string | null;
    fetchRawFiles: () => Promise<void>;
    uploadRawFile: (file: File, metadata?: Record<string, any>) => Promise<RawFile | null>;
    updateRawFile: (id: string, updates: Partial<RawFile>) => Promise<boolean>;
    deleteRawFile: (id: string) => Promise<boolean>;
    restoreRawFile: (id: string) => Promise<boolean>;
}

export function useRawFiles(): UseRawFilesReturn {
    const [rawFiles, setRawFiles] = useState<RawFile[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const fetchRawFiles = useCallback(async () => {
        try {
            setLoading(true);
            setError(null);

            const { data, error } = await supabase
                .from('raw_files')
                .select('*')
                .eq('is_deleted', false)
                .order('imported_at', { ascending: false });

            if (error) throw error;
            setRawFiles(data || []);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    }, []);

    const uploadRawFile = useCallback(async (
        file: File,
        metadata?: Record<string, any>
    ): Promise<RawFile | null> => {
        try {

            console.log('🔍 Début upload:', file.name);
            const fileExt = file.name.split('.').pop();
            const fileName = `${Date.now()}_${Math.random().toString(36).substring(7)}.${fileExt}`;
            const storagePath = `raw-files/${fileName}`;

            console.log('📁 Chemin storage:', storagePath);

            const { data: uploadData, error: uploadError } = await supabase.storage
                .from('document-files')
                .upload(storagePath, file, {
                    cacheControl: '3600',
                    upsert: false, // ✅ Ne pas écraser les fichiers existants
                    contentType: file.type,
                });

            if (uploadError) {
                console.error('❌ Erreur upload storage:', uploadError);
                console.error('❌ Détails:', uploadError.message);
                throw uploadError;
            }

            const { data: urlData } = supabase.storage
                .from('document-files')
                .getPublicUrl(storagePath);

            let fileType: 'pdf' | 'audio' | 'image' = 'pdf';
            if (file.type.startsWith('audio/')) fileType = 'audio';
            else if (file.type.startsWith('image/')) fileType = 'image';
            else if (file.type === 'application/pdf') fileType = 'pdf';

            const user = await supabase.auth.getUser();

            if (!user.data.user) {
                throw new Error('Utilisateur non authentifié');
            }

            const { data: dbData, error: dbError } = await supabase
                .from('raw_files')
                .insert({
                    file_name: file.name,
                    file_url: urlData.publicUrl,
                    file_type: fileType,
                    file_size: file.size,
                    mime_type: file.type,
                    storage_path: storagePath,
                    bucket_name: 'document-files',
                    metadata: metadata || {},
                    imported_by: user.data.user?.id,
                })
                .select()
                .single();

            if (dbError) {
                console.error('❌ Erreur DB:', dbError);
                throw dbError;
            }

            console.log('✅ Insert DB réussi:', dbData);

            setRawFiles(prev => [dbData, ...prev]);

            return dbData;
        } catch (err: any) {
            console.error('❌ Erreur upload complète:', err);
            console.error('❌ Message:', err.message);
            console.error('❌ Stack:', err.stack);
            setError(err.message);
            return null;
        }
    }, []);

    const updateRawFile = useCallback(async (
        id: string,
        updates: Partial<RawFile>
    ): Promise<boolean> => {
        try {
            const { error } = await supabase
                .from('raw_files')
                .update(updates)
                .eq('id', id);

            if (error) throw error;

            setRawFiles(prev => prev.map(f => f.id === id ? { ...f, ...updates } : f));

            return true;
        } catch (err: any) {
            setError(err.message);
            return false;
        }
    }, []);

    const deleteRawFile = useCallback(async (id: string): Promise<boolean> => {
        try {
            const user = await supabase.auth.getUser();

            const { error } = await supabase
                .from('raw_files')
                .update({
                    is_deleted: true,
                    deleted_at: new Date().toISOString(),
                    deleted_by: user.data.user?.id,
                })
                .eq('id', id);

            if (error) throw error;

            setRawFiles(prev => prev.filter(f => f.id !== id));

            return true;
        } catch (err: any) {
            setError(err.message);
            return false;
        }
    }, []);

    const restoreRawFile = useCallback(async (id: string): Promise<boolean> => {
        try {
            const { error } = await supabase
                .from('raw_files')
                .update({
                    is_deleted: false,
                    deleted_at: null,
                    deleted_by: null,
                })
                .eq('id', id);

            if (error) throw error;

            await fetchRawFiles();

            return true;
        } catch (err: any) {
            setError(err.message);
            return false;
        }
    }, [fetchRawFiles]);

    useEffect(() => {
        fetchRawFiles();
    }, [fetchRawFiles]);

    return {
        rawFiles,
        loading,
        error,
        fetchRawFiles,
        uploadRawFile,
        updateRawFile,
        deleteRawFile,
        restoreRawFile,
    };
}
